class Solution {

    private int[] w;
    private double[] prefixSum;

    public Solution(int[] w) {
        this.w = w;
        prefixSum = new double[w.length + 1];
        for (int i = 0; i < w.length; i++) {
            prefixSum[i + 1] = prefixSum[i] + (double) w[i] / w[w.length - 1];
        }
    }

    public int pickIndex() {
        double random = Math.random();
        for (int i = 0; i < w.length; i++) {
            if (random <= prefixSum[i + 1]) {
                return i;
            }
        }
        return w.length - 1;
    }
}
